<?php
/**
 * AJAX: Get Library Books
 * 
 * @author School ERP Development Team
 * @version 1.0.0
 */

// Start output buffering FIRST to catch any unwanted output
ob_start();

require_once '../../config/config.php';

// NOW suppress error display AFTER config is loaded
error_reporting(E_ALL);
ini_set('display_errors', 0);
ini_set('display_startup_errors', 0);

// Clear any output that might have been generated by config.php
ob_clean();

// Set JSON header early
header('Content-Type: application/json; charset=utf-8');
header('Cache-Control: no-cache, must-revalidate');

// Support both session-based (web) and user_id parameter (Flutter/mobile) authentication
$currentUser = null;
$userId = $_GET['user_id'] ?? $_POST['user_id'] ?? null;

if ($userId) {
    // Flutter/mobile app authentication
    $sql = "SELECT u.*, r.role_name, b.branch_name 
            FROM users u 
            LEFT JOIN roles r ON u.role_id = r.id 
            LEFT JOIN branches b ON u.branch_id = b.id 
            WHERE u.id = ? AND u.is_active = 1";
    $stmt = executeQuery($sql, 'i', [$userId]);
    $currentUser = fetchOne($stmt);
    
    if (!$currentUser) {
        jsonResponse(false, 'Invalid user ID');
    }
} else {
    // Web session-based authentication
    if (!isLoggedIn()) {
        jsonResponse(false, 'Unauthorized');
    }
    $currentUser = getCurrentUser();
}

$search = $_GET['search'] ?? null;
$category = $_GET['category'] ?? null;
$status = $_GET['status'] ?? null;

try {
    $sql = "SELECT b.*, br.branch_name,
            (SELECT COUNT(*) FROM library_issues li WHERE li.book_id = b.id AND li.status = 'Issued') as issued_count
            FROM library_books b
            LEFT JOIN branches br ON b.branch_id = br.id
            WHERE 1=1";
    
    $params = [];
    $types = '';
    
    // Branch filter
    if (!hasRole(['Super Admin']) && isset($currentUser['branch_id'])) {
        $sql .= " AND b.branch_id = ?";
        $params[] = $currentUser['branch_id'];
        $types .= 'i';
    }
    
    if ($search) {
        $sql .= " AND (b.book_title LIKE ? OR b.author LIKE ? OR b.isbn LIKE ? OR b.book_code LIKE ?)";
        $searchParam = "%$search%";
        $params[] = $searchParam;
        $params[] = $searchParam;
        $params[] = $searchParam;
        $params[] = $searchParam;
        $types .= 'ssss';
    }
    
    if ($category) {
        $sql .= " AND b.category = ?";
        $params[] = $category;
        $types .= 's';
    }
    
    $sql .= " ORDER BY b.book_title";
    
    $stmt = !empty($params) ? executeQuery($sql, $types, $params) : executeQuery($sql);
    $books = fetchAll($stmt);
    
    // Format the data
    $formatted = [];
    foreach ($books as $book) {
        $issuedCount = $book['issued_count'] ?? 0;
        $availableQuantity = max(0, $book['available_quantity'] - $issuedCount);
        
        $formatted[] = [
            'id' => $book['id'],
            'isbn' => $book['isbn'] ?? '',
            'book_title' => $book['book_title'],
            'author' => $book['author'] ?? '',
            'publisher' => $book['publisher'],
            'edition' => $book['publication_year'] ? (string)$book['publication_year'] : null,
            'category' => $book['category'],
            'quantity' => $book['quantity'] ?? 0,
            'available_quantity' => $availableQuantity,
            'location' => $book['location'],
            'status' => $availableQuantity > 0 ? 'Active' : 'Inactive',
            'added_at' => $book['added_at'],
        ];
    }
    
    jsonResponse(true, 'Books loaded', $formatted);
    
} catch (Exception $e) {
    jsonResponse(false, 'Failed to load books: ' . $e->getMessage());
}

